// === WF-08 [0] Parse Input ===
// Извлекаем chatId из тела POST-запроса от WF-01.
const raw = $input.first().json;
const body = raw.body || raw;
const chatId = String(body.chatId || '');
if (!chatId) {
  throw new Error('WF-08: chatId is required');
}
return [{ json: { chatId } }];

// Pass-through: сжимаем N строк Реестра обратно в 1 элемент, чтобы downstream-ноды не размножались.
// Сами данные доступны через $('Read Source Реестр').all().
return [$('Parse Input').first()];

// === WF-08 [1] Build Merged Dataset ===
// Объединяет Реестр + Банк в строки целевой схемы (21 колонка).
// Сопоставление документ↔платёж выполняется ПО ТЕМ ЖЕ правилам, что и /reconcile
// (WF-07, PATCH v1.1 §6):
//   Приоритет 0) Явная связь: Банк['UUID реестра'] уже заполнен (после /reconcile).
//   Иначе детерминированный матчинг внутри /update:
//     Шаг 0 (предфильтр): Страна==Страна, Статус==Статус, Валюта==Валюта,
//       |Сумма реестра| ≈ |Сумма банка| (допуск ±0.02);
//       кандидаты — только строки Реестра со «Статус оплаты = Оплачено».
//     Шаг 1: по номеру инвойса (нормализованный).
//     Шаг 2: по контрагенту (нормализованный, без юр.форм).
// Результат:
//   matched  → одна объединённая строка (документ из Реестра + платёж из Банка);
//   Реестр без пары → reg-only; Банк без пары → bank-only.
// Затем: сортировка по дате, нумерация Nr = 1..N, smart upsert ручных правок из target.

const sourceReg  = $('Read Source Реестр').all().map(i => i.json);
const sourceBank = $('Read Source Банк').all().map(i => i.json);
const oldTarget  = $('Read Target Реестр').all().map(i => i.json);

const MANUAL_COLS = ['Тип документа', 'Товар или услуга', 'Ед измерения', 'Количество', 'Стоимость', 'НДС', 'В бухгалтерию'];
const AMOUNT_TOLERANCE = 0.02;

function num(v) {
  if (v === '' || v === null || v === undefined) return NaN;
  const n = parseFloat(String(v).replace(/\s/g, '').replace(',', '.'));
  return Number.isFinite(n) ? n : NaN;
}
function amountOut(v) {
  const n = num(v);
  return Number.isFinite(n) ? n : '';
}
function lc(v) { return String(v == null ? '' : v).trim().toLowerCase(); }
function uc(v) { return String(v == null ? '' : v).trim().toUpperCase(); }

function parseDate(s) {
  if (!s) return 0;
  const m = String(s).match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
  if (m) return new Date(parseInt(m[3], 10), parseInt(m[2], 10) - 1, parseInt(m[1], 10)).getTime();
  const d = Date.parse(s);
  return Number.isFinite(d) ? d : 0;
}

function normInvoice(s) {
  if (!s || String(s).trim() === '') return null;
  return String(s).toLowerCase().replace(/\s+/g, '');
}
function normCounterparty(s) {
  if (!s || String(s).trim() === '') return null;
  // Любой не-буквенно-цифровой символ -> пробел (точки в "sp. z o.o." тоже).
  let n = String(s).toLowerCase().replace(/[^a-zа-яё0-9]+/gi, ' ').replace(/\s+/g, ' ').trim();
  if (!n) return null;
  // Многословные латинские юр.формы (\b для латиницы работает корректно).
  n = n.replace(/\bsp\s*z\s*o\s*o\b/g, ' ')
       .replace(/\bs\s*a\b/g, ' ')
       .replace(/\bsp\s*[jk]\b/g, ' ');
  // Однословные юр.формы (RU/BY/PL/EN) удаляем как целые токены — script-agnostic,
  // не зависит от \b (который в JS не видит границы кириллицы).
  const drop = new Set(['ооо','зао','оао','одо','чуп','уп','ип','spzoo','zoo','ltd','gmbh','inc','llc','sarl','sas']);
  n = n.split(' ').filter(t => t && !drop.has(t)).join(' ').trim();
  return n || null;
}
function isPaid(r) { return lc(r['Статус оплаты']) === 'оплачено'; }

// Индекс Реестра по UUID — для явной связи, проставленной /reconcile
const regByUuid = new Map();
sourceReg.forEach((r, i) => {
  const uuid = String(r['UUID'] || '').trim();
  if (uuid) regByUuid.set(uuid, i);
});

const regUsed = new Array(sourceReg.length).fill(false);
const merged = [];

// Возвращает индекс реестровой пары для банковской строки или -1.
function findRegMatch(b) {
  // Приоритет 0: явная UUID-связь (после /reconcile)
  const bUuid = String(b['UUID реестра'] || '').trim();
  if (bUuid && regByUuid.has(bUuid)) {
    const idx = regByUuid.get(bUuid);
    if (!regUsed[idx]) return idx;
  }

  // Шаг 0: предфильтр кандидатов
  const bAmt = num(b['Сумма']);
  const bCountry = lc(b['Страна']);
  const bStatus = lc(b['Статус']);
  const bCur = uc(b['Валюта']);
  const cands = [];
  for (let i = 0; i < sourceReg.length; i++) {
    if (regUsed[i]) continue;
    const r = sourceReg[i];
    if (!isPaid(r)) continue;
    if (lc(r['Страна']) !== bCountry) continue;
    if (lc(r['Статус']) !== bStatus) continue;
    if (uc(r['Валюта']) !== bCur) continue;
    const rAmt = num(r['Сумма']);
    if (!Number.isFinite(rAmt) || !Number.isFinite(bAmt)) continue;
    if (Math.abs(Math.abs(rAmt) - Math.abs(bAmt)) > AMOUNT_TOLERANCE) continue;
    cands.push(i);
  }
  if (!cands.length) return -1;

  // Шаг 1: по номеру инвойса
  const bInv = normInvoice(b['Номер инвойса (банк)']);
  if (bInv) {
    const hit = cands.find(i => normInvoice(sourceReg[i]['Номер инвойса']) === bInv);
    if (hit !== undefined) return hit;
  }
  // Шаг 2: по контрагенту
  const bCP = normCounterparty(b['Контрагент']);
  if (bCP) {
    const hit = cands.find(i => normCounterparty(sourceReg[i]['Контрагент']) === bCP);
    if (hit !== undefined) return hit;
  }
  return -1;
}

// Проход 1: банковские строки → matched | bankOnly
for (const b of sourceBank) {
  const idx = findRegMatch(b);
  if (idx >= 0) {
    regUsed[idx] = true;
    const r = sourceReg[idx];
    merged.push({
      _type: 'matched',
      _sortDate: parseDate(r['Дата документа'] || b['Дата документа'] || b['Дата оплаты']),
      'Nr': 0,
      'ID': r['Nr ID'] || '',
      'Статус': r['Статус'] || b['Статус'] || '',
      'Дата документа': r['Дата документа'] || '',
      'Тип документа': '',
      'Номер документа': r['Номер инвойса'] || b['Номер инвойса (банк)'] || '',
      'Контрагент': r['Контрагент'] || b['Контрагент'] || '',
      'Товар или услуга': '',
      'Ед измерения': '',
      'Количество': '',
      'Стоимость': '',
      'НДС': '',
      'Сумма брутто': amountOut(r['Сумма']),
      'Дата оплаты': b['Дата оплаты'] || r['Дата оплаты'] || '',
      'Сумма оплаты': amountOut(b['Сумма']),
      'Счет / Источник': b['Банк'] || '',
      'В бухгалтерию': '',
      'Статус оплаты': r['Статус оплаты'] || 'Оплачено',
      'Страна': r['Страна'] || b['Страна'] || '',
      'Ссылка на документ': r['Ссылка на документ'] || '',
      'Описание ИИ': r['Описание AI'] || b['Описание'] || ''
    });
  } else {
    merged.push({
      _type: 'bankOnly',
      _sortDate: parseDate(b['Дата документа'] || b['Дата оплаты']),
      'Nr': 0,
      'ID': b['bank_id'] || '',
      'Статус': b['Статус'] || '',
      'Дата документа': b['Дата документа'] || '',
      'Тип документа': '',
      'Номер документа': b['Номер инвойса (банк)'] || '',
      'Контрагент': b['Контрагент'] || '',
      'Товар или услуга': '',
      'Ед измерения': '',
      'Количество': '',
      'Стоимость': '',
      'НДС': '',
      'Сумма брутто': '',
      'Дата оплаты': b['Дата оплаты'] || '',
      'Сумма оплаты': amountOut(b['Сумма']),
      'Счет / Источник': b['Банк'] || '',
      'В бухгалтерию': '',
      'Статус оплаты': 'Оплачено',
      'Страна': b['Страна'] || '',
      'Ссылка на документ': '',
      'Описание ИИ': b['Описание'] || ''
    });
  }
}

// Проход 2: Реестр-only (строки, не использованные при матчинге)
for (let i = 0; i < sourceReg.length; i++) {
  if (regUsed[i]) continue;
  const r = sourceReg[i];
  merged.push({
    _type: 'regOnly',
    _sortDate: parseDate(r['Дата документа'] || r['Дата оплаты']),
    'Nr': 0,
    'ID': r['Nr ID'] || '',
    'Статус': r['Статус'] || '',
    'Дата документа': r['Дата документа'] || '',
    'Тип документа': '',
    'Номер документа': r['Номер инвойса'] || '',
    'Контрагент': r['Контрагент'] || '',
    'Товар или услуга': '',
    'Ед измерения': '',
    'Количество': '',
    'Стоимость': '',
    'НДС': '',
    'Сумма брутто': amountOut(r['Сумма']),
    'Дата оплаты': r['Дата оплаты'] || '',
    'Сумма оплаты': '',
    'Счет / Источник': '',
    'В бухгалтерию': '',
    'Статус оплаты': r['Статус оплаты'] || '',
    'Страна': r['Страна'] || '',
    'Ссылка на документ': r['Ссылка на документ'] || '',
    'Описание ИИ': r['Описание AI'] || ''
  });
}

// Сортировка по дате (документа, fallback оплаты)
merged.sort((a, b) => a._sortDate - b._sortDate);

// Smart upsert: индекс старого target по ID, копируем ручные правки
const oldByID = new Map();
for (const o of oldTarget) {
  const id = String(o['ID'] || '').trim();
  if (id) oldByID.set(id, o);
}

const stats = { matched: 0, regOnly: 0, bankOnly: 0, preserved: 0, total: merged.length };
const output = [];
for (let i = 0; i < merged.length; i++) {
  const row = merged[i];
  row['Nr'] = i + 1;
  const id = String(row['ID'] || '').trim();
  if (id && oldByID.has(id)) {
    const old = oldByID.get(id);
    for (const col of MANUAL_COLS) {
      const oldVal = old[col];
      if (oldVal !== undefined && oldVal !== '' && oldVal !== null) {
        if (!row[col]) {
          row[col] = oldVal;
          stats.preserved++;
        }
      }
    }
  }
  if (row._type === 'matched') stats.matched++;
  else if (row._type === 'regOnly') stats.regOnly++;
  else stats.bankOnly++;
  delete row._type;
  delete row._sortDate;
  output.push({ json: row });
}

// Прикрепляем stats + chatId к первому элементу для downstream-нод
const chatId = $('Parse Input').first().json.chatId;
if (output.length > 0) {
  output[0].json._stats = stats;
  output[0].json._chatId = chatId;
} else {
  output.push({ json: { _empty: true, _chatId: chatId, _stats: stats, 'Nr': '', 'ID': '', 'Статус': '', 'Дата документа': '', 'Тип документа': '', 'Номер документа': '', 'Контрагент': '', 'Товар или услуга': '', 'Ед измерения': '', 'Количество': '', 'Стоимость': '', 'НДС': '', 'Сумма брутто': '', 'Дата оплаты': '', 'Сумма оплаты': '', 'Счет / Источник': '', 'В бухгалтерию': '', 'Статус оплаты': '', 'Страна': '', 'Ссылка на документ': '', 'Описание ИИ': '' } });
}

return output;

// === WF-08 Restore Rows ===
// 'Clear Target Data' стоит на Execute Once и пропускает дальше только 1 item,
// из-за чего Append добавлял лишь одну строку. Здесь восстанавливаем ПОЛНЫЙ
// набор объединённых строк, чтобы Append записал их все.
return $('Build Merged Dataset').all();

// === WF-08 [9] Build Confirmation ===
// Берём stats из первого item Build Merged Dataset и формируем Telegram-сообщение.

const built = $('Build Merged Dataset').first().json;
const stats = built._stats || { matched: 0, regOnly: 0, bankOnly: 0, preserved: 0, total: 0 };
const chatId = built._chatId || $('Parse Input').first().json.chatId;

const targetUrl = 'https://docs.google.com/spreadsheets/d/1srpRh2TgHZY8W-wkmgSTlV4vhxplT_PBhNz-Cd3w-U8/edit';

let text;
if (stats.total === 0) {
  text = '\u26A0\uFE0F В исходных Реестре и Банке нет данных. Целевой документ очищен.';
} else {
  text =
    '\u2705 Реестр обновлён\n\n' +
    '\uD83D\uDCCA Всего строк: ' + stats.total + '\n' +
    '\uD83D\uDD17 С документом и оплатой: ' + stats.matched + '\n' +
    '\uD83D\uDCC4 Только документ (без оплаты): ' + stats.regOnly + '\n' +
    '\uD83D\uDCB3 Только оплата (без документа): ' + stats.bankOnly + '\n';
  if (stats.preserved > 0) {
    text += '\u270F\uFE0F Сохранено ручных правок: ' + stats.preserved + '\n';
  }
  text += '\n\uD83D\uDCCB ' + targetUrl;
}

return [{ json: { chatId, text, _stats: stats } }];

// === WF-08 [E] Build Error ===
let chatId = '';
try { chatId = String($('Parse Input').first().json.chatId || ''); } catch (e) {}
if (!chatId) {
  try { chatId = String($input.first().json.execution?.customData?.chatId || ''); } catch (e) {}
}
const stepName = $input.first().json.node?.name || $input.first().json.execution?.error?.node?.name || 'неизвестный';
const errMsg = $input.first().json.execution?.error?.message || $input.first().json.error?.message || 'неизвестная ошибка';
return [{ json: { chatId, text: '\u274C WF-08 /update упал.\n\n*Шаг:* ' + stepName + '\n*Ошибка:* ' + errMsg } }];
